// ❌ BAD - no null check; crashes if user is null or has no address
public string GetCity(int userId) {
    var user = _db.Users.FirstOrDefault(u => u.Id == userId);
    return user.Address.City; // NullReferenceException if user is null
}

// ✅ GOOD - null-conditional chain; safe and readable
public string GetCity(int userId) {
    var user = _db.Users.FirstOrDefault(u => u.Id == userId);
    return user?.Address?.City ?? "Unknown";
}
// With nullable reference types enabled, compiler flags user.Address.City without guard

// ❌ BAD - checking .Length without a null guard
public bool IsEmptyEmail(string email) =>
    email.Length == 0; // NullReferenceException if email is null

// ✅ GOOD - IsNullOrWhiteSpace handles null, empty, and whitespace
public bool IsEmptyEmail(string? email) =>
    string.IsNullOrWhiteSpace(email);

