// ❌ BAD - trying to inherit from an enum; compile error
public enum BaseStatus { Active, Inactive }
public enum ExtendedStatus : BaseStatus { Suspended } // compile error

// ✅ GOOD - extension methods add behaviour; smart-enum adds polymorphism
public enum OrderStatus { Pending, Shipped, Cancelled }
public static class OrderStatusExtensions {
    public static bool IsTerminal(this OrderStatus s) =>
        s == OrderStatus.Shipped || s == OrderStatus.Cancelled;
}
// Usage: if (order.Status.IsTerminal()) { ... }

